#include <stdio.h>
#include <stdlib.h>

#define RADIX 255

static long range = 1;
static long low = 0;
static int cc[2000000];
static int emitted_count = 0;

static void emit_digit(int d){
    emitted_count++;
    fprintf(stderr, "EMIT digit=%d emitted_count=%d low=%ld range=%ld\n", d, emitted_count, low, range);
    putchar((unsigned char)((d+1)&0xFF));
}
static void normalize_encoder(void){
    while(range < RADIX){
        long digit = low / RADIX;
        low = (low - digit * RADIX) * RADIX;
        range *= RADIX;
        emit_digit((int)digit);
    }
}
static void put_bit(int ctx,int bit){
    normalize_encoder();
    int idx=ctx*2;
    int c0=cc[idx], c1=cc[idx+1];
    long split = range * (c0 + 1) / (c0 + c1 + 2);
    if(bit==1){
        low += split;
        range -= split;
    }else{
        range = split;
    }
    cc[idx+bit]++;
    fprintf(stderr, "ENC put_bit ctx=%d bit=%d split=%ld low=%ld range=%ld c0=%d c1=%d\n", ctx, bit, split, low, range, c0, c1);
}
static void encode_integer(int start,int ctx,int value){
    long result=(long)value+(1L<<start);
    int k = 0;
    while((1L<<(k+1)) <= result) k++;
    int ctx2 = ctx * 99;
    fprintf(stderr,"ENC encode_integer value=%d result=%ld k=%d start=%d\n", value, result, k, start);
    for(int t=start+1; t<=start+k-1; t++) put_bit(t+ctx2,0);
    put_bit(start+k+ctx2,1);
    for(int i=k-1;i>=0;i--) put_bit(ctx,(int)((result>>i)&1));
}
static void finish(void){
    normalize_encoder();
    for(int i=0;i<8;i++){
        long digit = low / RADIX;
        low = (low - digit * RADIX) * RADIX;
        range *= RADIX;
        emit_digit((int)digit);
    }
}
int main(void){
    encode_integer(9,0,7);
    finish();
    return 0;
}
