#include <stdio.h>
#include <stdlib.h>

#define W for (i=0;i<tmp;i++)

int i;
int radix = 255;
int fraction;
long range = 1;
int tmp;
int cc[1000000];
static int read_count = 0;

int gc() {
  int c = getchar();
  if (c == EOF) { fprintf(stderr, "EOF in gc\n"); exit(1); }
  read_count++;
  fprintf(stderr, "READ byte=%d read_count=%d fraction=%d range=%ld\n", c, read_count, fraction, range);
  return (int)(unsigned char)c;
}

int get_bit(int ctx) {
  int normed = 0;
  if ( range < radix ) {
    range *= radix;
    fraction *= radix;
    fraction += gc()-1;
    normed = 1;
  }
  int *counts = cc + ctx * 2;
  int split = range * -~*counts / (*counts + counts[ 1 ] + 2);
  int the_bit = fraction >= split;
  fraction -= split*the_bit;
  range = the_bit ? range-split : split;
  counts[ the_bit ]++;
  fprintf(stderr, "DEC get_bit ctx=%d bit=%d split=%d fraction=%d range=%ld c0=%d c1=%d normed=%d\n", ctx, the_bit, split, fraction, range, counts[0], counts[1], normed);
  return the_bit;
}

int get_integer(int tmp_arg, int ctx) {
  int subtract_it = 1<<tmp_arg;
  int result_ans = 1;
  int local_tmp = tmp_arg;
  int orig_ctx = ctx;
  ctx*=99;
  while (!get_bit(++local_tmp+ctx));
  local_tmp--;
  tmp = local_tmp;
  fprintf(stderr, "DEC get_integer stop_tmp=%d payload_bits=%d\n", local_tmp+1, local_tmp);
  W {
    int b = get_bit(orig_ctx);
    result_ans = result_ans*2 | b;
  }
  return result_ans - subtract_it;
}

int main(void) {
  int v = get_integer(9,0);
  printf("decoded=%d\n", v);
  return 0;
}
